// CORRECT: structural privacy gate — T90 is branch entry
@EventPattern('QuestionnaireAnswered')
async handleSocialShareGate(input): Promise<DataProcessResult<SocialShareGateResult>> {
  const privacy = await this.privacyService.check(input.userId);
  if (privacy.isPrivate) return DataProcessResult.success({ shared: false });
  await this.queue.enqueue('SocialShareApproved', { userId: input.userId, questionnaireId: input.questionnaireId });
  return DataProcessResult.success({ shared: true });
}
